defmodule BlogWeb.PostView do
  use BlogWeb, :view

  def render("show.html", assigns) do
    ~H"""
    <div class="post-content">
      <%= raw @post.content %>
    </div>
    """
  end
end

defmodule BlogWeb.PostController do
  use BlogWeb, :controller

  def show(conn, %{"id" => id}) do
    post = Blog.get_post!(id)
    render(conn, "show.html", post: post)
  end
end

defmodule BlogWeb.PostLive do
  use Phoenix.LiveView

  def render(assigns) do
    ~H"""
    <div class="post-content">
      <%= raw @post.content %>
    </div>
    """
  end

  def mount(%{"id" => id}, _session, socket) do
    post = Blog.get_post!(id)
    {:ok, assign(socket, post: post)}
  end
end

defmodule BlogWeb.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content])
    |> validate_required([:title, :content])
  end
end

defmodule BlogWeb.Sanitize do
  def sanitize_html(html) do
    html
    |> strip_tags()
    |> sanitize_attributes()
  end

  defp strip_tags(html) do
    html
    |> String.replace(~r/<script[^>]*>.*?<\/script>/i, "")
    |> String.replace(~r/<iframe[^>]*>.*?<\/iframe>/i, "")
    |> String.replace(~r/<object[^>]*>.*?<\/object>/i, "")
    |> String.replace(~r/<embed[^>]*>.*?<\/embed>/i, "")
  end

  defp sanitize_attributes(html) do
    html
    |> String.replace(~r/on\w+\s*=\s*["'][^"']*["']/i, "")
  end
end